const MyCollapsible: ObjectIndependentInput = (props) => {
  const { name, meta } = props;
  const [open, setOpen] = React.useState(true);

  useErrorChecker({ name, meta, open, setOpen });

  return (
    <AccordeonCard name={name} header={<span>Section</span>} open={open} onToggle={setOpen}>
      {/* child controllers */}
    </AccordeonCard>
  );
};

const CustomOneOf: ObjectIndependentInput = (props) => {
  const { name, input, spec } = props;
  const { oneOfValue, specProperties, toggler } = useOneOf({ props });

  const parentOnChange = React.useCallback(
    (childName, childValue, childErrors) => {
      const value = set({}, childName.split(`${input.name}.`).join(''), childValue);
      input.onChange(value, childErrors);
    },
    [input.onChange, input.name],
  );

  return (
    <div>
      {toggler}
      {specProperties[oneOfValue] && (
        <GroupIndent>
          <Controller
            value={input.value?.[oneOfValue]}
            spec={specProperties[oneOfValue]}
            name={`${name}.${oneOfValue}`}
            parentOnChange={parentOnChange}
            parentOnUnmount={input.parentOnUnmount}
          />
        </GroupIndent>
      )}
    </div>
  );
};

